#!/usr/bin/env python3
"""
Add all remaining missing AMI-standard works to the Montessori Brain.
Updates both stem/*.json and comprehensive-guides/*.json.
"""
import json, os

BASE = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
STEM = os.path.join(BASE, 'lib', 'montree', 'stem')
GUIDES = os.path.join(BASE, 'lib', 'curriculum', 'comprehensive-guides')

def add_to_stem(filename, cat_name, works, new_cat_seq=None):
    path = os.path.join(STEM, filename)
    with open(path) as f: data = json.load(f)
    found = False
    for cat in data['categories']:
        if cat['name'] == cat_name:
            ids = {w['id'] for w in cat['works']}
            for w in works:
                if w['id'] not in ids:
                    cat['works'].append(w)
                    print(f"  + stem: {w['name']}")
            found = True; break
    if not found and new_cat_seq:
        data['categories'].append({"name": cat_name, "sequence": new_cat_seq, "works": works})
        for w in works: print(f"  + stem (new cat): {w['name']}")
    with open(path, 'w') as f: json.dump(data, f, indent=2, ensure_ascii=False)

def add_to_guides(filename, guides):
    path = os.path.join(GUIDES, filename)
    with open(path) as f: data = json.load(f)
    wlist = data.get('works', data) if isinstance(data, dict) else data
    ids = {w.get('work_id') for w in wlist}
    for g in guides:
        if g['work_id'] not in ids:
            wlist.append(g)
            print(f"  + guide: {g['name']}")
    if isinstance(data, dict) and 'works' in data: data['works'] = wlist
    with open(path, 'w') as f: json.dump(data, f, indent=2, ensure_ascii=False)

def mk_stem(id, name, desc, age, prereqs, seq, mats, da, ia, coe, cn, levels):
    return {"id":id,"name":name,"description":desc,"ageRange":age,"prerequisites":prereqs,
            "sequence":seq,"materials":mats,"directAims":da,"indirectAims":ia,
            "controlOfError":coe,"chineseName":cn,"levels":levels}

def mk_guide(wid, name, cn, slug, area, cat, seq, age, qg, steps, da, ia, mats, coe, prereqs, poi, var, cc, vst, pd, wim):
    return {"work_id":wid,"name":name,"name_chinese":cn,"slug":slug,"area":area,"category":cat,
            "sequence":seq,"age_range":age,"quick_guide":qg,"presentation_steps":steps,
            "direct_aims":da,"indirect_aims":ia,"materials_needed":mats,"control_of_error":coe,
            "prerequisites":prereqs,"points_of_interest":poi,"variations":var,
            "common_challenges":cc,"video_search_term":vst,"parent_description":pd,"why_it_matters":wim}

def S(n,t,d,tip): return {"step":n,"title":t,"description":d,"tip":tip}
def L(n,nm,d,v): return {"level":n,"name":nm,"description":d,"videoSearchTerms":v}


